class Solution:
    def findValueOfPartition(self, nums):
        n = len(nums)
        best = None
        for mask in range(1, (1 << n) - 1):
            g1 = [nums[i] for i in range(n) if mask & (1 << i)]
            g2 = [nums[i] for i in range(n) if not (mask & (1 << i))]
            val = abs(max(g1) - min(g2))
            if best is None or val < best:
                best = val
        return best

