var findValueOfPartition = function(nums) {
    const s = nums.slice().sort((a, b) => a - b);
    let best = Infinity;
    for (let i = 0; i + 1 < s.length; i++) {
        const gap = s[i + 1] - s[i];
        if (gap < best) best = gap;
    }
    return best;
};
